import{_ as a,H as i,f as t,i as n}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"IO 五种模型","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/20-IO五种模型.md","filePath":"osLearning/20-IO五种模型.md","lastUpdated":1778496697000}'),e={name:"osLearning/20-IO五种模型.md"};function l(p,s,h,d,r,o){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="io-五种模型" tabindex="-1">IO 五种模型 <a class="header-anchor" href="#io-五种模型" aria-label="Permalink to &quot;IO 五种模型&quot;">​</a></h1><p>IO 模型回答一个问题:当数据还没准备好时,线程怎么办。阻塞 IO 让线程睡,非阻塞 IO 立刻返回,多路复用让一个线程等多个 fd,信号驱动 IO 用信号通知,异步 IO 则让内核完成后告诉你结果。很多人把&quot;同步/异步&quot;和&quot;阻塞/非阻塞&quot;混着用,导致理解 epoll、io_uring、Node、Nginx、Go netpoller 时全乱。这一篇把五种模型一次讲清楚。</p><blockquote><p>一句话先记住:<strong>阻塞/非阻塞说的是调用会不会卡住线程,同步/异步说的是数据拷贝由谁完成</strong>。epoll 是同步 IO 多路复用:它只告诉你 fd 就绪,真正 <code>read/write</code> 还得你自己做。io_uring 更接近异步 IO:你提交操作,完成后拿结果。<strong>高性能网络的主流不是&quot;一个连接一个线程&quot;,而是非阻塞 fd + IO 多路复用 + 事件循环</strong>。</p></blockquote><hr><h2 id="一、一次-io-的两个阶段" tabindex="-1">一、一次 IO 的两个阶段 <a class="header-anchor" href="#一、一次-io-的两个阶段" aria-label="Permalink to &quot;一、一次 IO 的两个阶段&quot;">​</a></h2><p>以 socket read 为例:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段 1: 等数据到达内核缓冲区</span></span>
<span class="line"><span>阶段 2: 从内核缓冲区拷贝到用户 buffer</span></span></code></pre></div><p>不同 IO 模型,差别就在这两阶段谁等、怎么等。</p><hr><h2 id="二、阻塞-io" tabindex="-1">二、阻塞 IO <a class="header-anchor" href="#二、阻塞-io" aria-label="Permalink to &quot;二、阻塞 IO&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4096</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>没数据时线程睡眠:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户线程 read</span></span>
<span class="line"><span>  → 内核:没数据</span></span>
<span class="line"><span>  → 线程睡眠</span></span>
<span class="line"><span>  → 数据到达,中断唤醒</span></span>
<span class="line"><span>  → 内核拷贝数据</span></span>
<span class="line"><span>  → read 返回</span></span></code></pre></div><p>优点:</p><ul><li>编程简单</li><li>适合少量连接</li></ul><p>缺点:</p><ul><li>一个连接占一个线程/进程</li><li>高并发下内存和调度成本高</li></ul><hr><h2 id="三、非阻塞-io" tabindex="-1">三、非阻塞 IO <a class="header-anchor" href="#三、非阻塞-io" aria-label="Permalink to &quot;三、非阻塞 IO&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETFL, O_NONBLOCK);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4096</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> errno </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EAGAIN) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 没数据,下次再试</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>没数据立即返回 <code>EAGAIN</code>。</p><p>优点:</p><ul><li>线程不被卡死</li><li>是事件循环的基础</li></ul><p>缺点:</p><ul><li>如果自己 while 轮询,CPU 空转</li></ul><p>错误写法:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">while</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, n) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> errno </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EAGAIN) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 空转烧 CPU</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>所以非阻塞通常要配合 epoll/kqueue。</p><hr><h2 id="四、io-多路复用" tabindex="-1">四、IO 多路复用 <a class="header-anchor" href="#四、io-多路复用" aria-label="Permalink to &quot;四、IO 多路复用&quot;">​</a></h2><p>一个线程等多个 fd:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">epoll_wait</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(epfd, events, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>流程:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>注册多个 fd</span></span>
<span class="line"><span>epoll_wait 睡眠</span></span>
<span class="line"><span>任意 fd 就绪 → 唤醒</span></span>
<span class="line"><span>用户态 read/write</span></span></code></pre></div><p>select/poll/epoll 都属于这个模型。</p><table tabindex="0"><thead><tr><th>API</th><th>问题</th></tr></thead><tbody><tr><td>select</td><td>fd 上限 1024,每次全量拷贝扫描</td></tr><tr><td>poll</td><td>无 1024 限制,但仍全量扫描</td></tr><tr><td>epoll</td><td>内核维护集合,只返回就绪 fd</td></tr></tbody></table><p><strong>注意</strong>:epoll 不是异步 IO。它只通知&quot;可以读/写&quot;,数据拷贝仍发生在你调用 <code>read/write</code> 时。</p><hr><h2 id="五、信号驱动-io" tabindex="-1">五、信号驱动 IO <a class="header-anchor" href="#五、信号驱动-io" aria-label="Permalink to &quot;五、信号驱动 IO&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETOWN, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getpid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">());</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETFL, O_ASYNC </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> O_NONBLOCK);</span></span></code></pre></div><p>数据就绪时内核发 <code>SIGIO</code>。</p><p>优点:</p><ul><li>线程不用阻塞等</li></ul><p>缺点:</p><ul><li>信号语义复杂</li><li>可重入和异步信号安全限制多</li><li>工程上很少用于通用网络服务器</li></ul><p>现代 Linux 更常用 epoll/signalfd,很少直接用 SIGIO 做网络主模型。</p><hr><h2 id="六、异步-io" tabindex="-1">六、异步 IO <a class="header-anchor" href="#六、异步-io" aria-label="Permalink to &quot;六、异步 IO&quot;">​</a></h2><p>异步 IO 的目标:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提交 read 请求</span></span>
<span class="line"><span>内核等待数据 + 拷贝数据</span></span>
<span class="line"><span>完成后通知用户</span></span>
<span class="line"><span>用户拿到结果</span></span></code></pre></div><p>Linux 历史上的 POSIX AIO 对普通文件支持有限,网络也不理想。真正改变局面的是 io_uring:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">io_uring_prep_read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sqe, fd, buf, len, offset);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">io_uring_submit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ring</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">io_uring_wait_cqe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ring</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">cqe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>io_uring 把文件、socket、timeout、accept、send 等都统一成提交队列/完成队列。</p><hr><h2 id="七、同步-异步-vs-阻塞-非阻塞" tabindex="-1">七、同步/异步 vs 阻塞/非阻塞 <a class="header-anchor" href="#七、同步-异步-vs-阻塞-非阻塞" aria-label="Permalink to &quot;七、同步/异步 vs 阻塞/非阻塞&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>等数据</th><th>拷贝数据</th><th>典型 API</th></tr></thead><tbody><tr><td>阻塞 IO</td><td>内核里睡</td><td>调用线程做</td><td>blocking read</td></tr><tr><td>非阻塞 IO</td><td>立即返回</td><td>调用线程做</td><td>O_NONBLOCK read</td></tr><tr><td>多路复用</td><td>epoll_wait 等</td><td>调用线程做</td><td>epoll + read</td></tr><tr><td>信号驱动</td><td>信号通知</td><td>调用线程做</td><td>SIGIO</td></tr><tr><td>异步 IO</td><td>内核处理</td><td>内核完成</td><td>io_uring/AIO</td></tr></tbody></table><p>重点:</p><ul><li>epoll 是同步非阻塞体系的一部分</li><li>async/await 是语言抽象,底层可能是 epoll,不一定是内核异步 IO</li><li>Go 网络 IO 看起来阻塞,底层是 nonblocking fd + netpoller</li></ul><hr><h2 id="八、reactor-与-proactor" tabindex="-1">八、Reactor 与 Proactor <a class="header-anchor" href="#八、reactor-与-proactor" aria-label="Permalink to &quot;八、Reactor 与 Proactor&quot;">​</a></h2><h3 id="_8-1-reactor" tabindex="-1">8.1 Reactor <a class="header-anchor" href="#_8-1-reactor" aria-label="Permalink to &quot;8.1 Reactor&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事件循环等&quot;就绪&quot;</span></span>
<span class="line"><span>就绪后用户态处理 read/write</span></span></code></pre></div><p>epoll/Nginx/Redis/Node 大多是 Reactor。</p><h3 id="_8-2-proactor" tabindex="-1">8.2 Proactor <a class="header-anchor" href="#_8-2-proactor" aria-label="Permalink to &quot;8.2 Proactor&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提交操作</span></span>
<span class="line"><span>内核/运行时完成操作</span></span>
<span class="line"><span>回调处理结果</span></span></code></pre></div><p>Windows IOCP、io_uring 更接近 Proactor。</p><hr><h2 id="九、模型选择" tabindex="-1">九、模型选择 <a class="header-anchor" href="#九、模型选择" aria-label="Permalink to &quot;九、模型选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐</th></tr></thead><tbody><tr><td>简单脚本/少连接</td><td>阻塞 IO</td></tr><tr><td>高并发网络</td><td>非阻塞 + epoll/kqueue</td></tr><tr><td>文件 + 网络混合高性能</td><td>io_uring</td></tr><tr><td>语言 runtime</td><td>封装 epoll/io_uring,暴露 async/协程</td></tr><tr><td>信号通知</td><td>signalfd 或事件循环集成</td></tr></tbody></table><hr><h2 id="十、常见坑" tabindex="-1">十、常见坑 <a class="header-anchor" href="#十、常见坑" aria-label="Permalink to &quot;十、常见坑&quot;">​</a></h2><ol><li><strong>非阻塞 fd 忘处理 EAGAIN</strong>:把正常状态当错误。</li><li><strong>epoll ET 不读到 EAGAIN</strong>:数据卡住。</li><li><strong>一直监听 EPOLLOUT</strong>:CPU 空转。</li><li><strong>async 函数里调用阻塞 IO</strong>:事件循环被卡死。</li><li><strong>以为 epoll 会帮你读数据</strong>:它只告诉你就绪。</li><li><strong>文件 fd 用 epoll</strong>:普通文件通常总是 ready,不适合 epoll 等待。</li></ol><blockquote><p><strong>结论</strong>:IO 模型的核心不是术语,而是&quot;等待发生在哪里&quot;。高性能服务的基本盘是:fd 非阻塞、等待交给 epoll/io_uring、业务层必须处理短读短写和背压。</p></blockquote>`,73)])])}const g=a(e,[["render",l]]);export{c as __pageData,g as default};
